mapper.select:
SELECT d.id AS "drugId", d.drug_name AS "drugName", d.drug_format AS "drugFormat", d.drug_unit AS "drugUnit", d.drug_dosage AS "drugDosage", d.manufacturer AS "manufacturer", d.drug_type AS "drugType", 'catalog' AS "source" FROM drug_info d
AND ( d.drug_name ILIKE CONCAT('%', #{keyword}, '%') OR d.mnemonic_code ILIKE CONCAT('%', #{keyword}, '%') OR d.drug_code ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY d.drug_name ASC LIMIT #{limit}

SELECT r.deptment_id
FROM register r
WHERE r.id = #{registerId}
